import React from 'react';
import Svg, {Path, G, Circle, Line, Polyline, Rect} from 'react-native-svg';

export interface IconProps {
  size?: number;
  color?: string;
  filled?: boolean;
  strokeWidth?: number;
}

const defaults = {size: 24, color: '#888', strokeWidth: 1.8};

function I({
  size = defaults.size,
  color = defaults.color,
  children,
}: IconProps & {children: React.ReactNode}) {
  return (
    <Svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      stroke={color}
      strokeWidth={defaults.strokeWidth}
      strokeLinecap="round"
      strokeLinejoin="round">
      {children}
    </Svg>
  );
}

export function HeartIcon({size, color, filled, strokeWidth}: IconProps) {
  const sw = strokeWidth ?? defaults.strokeWidth;
  return (
    <Svg
      width={size ?? defaults.size}
      height={size ?? defaults.size}
      viewBox="0 0 24 24"
      fill={filled ? color ?? defaults.color : 'none'}
      stroke={color ?? defaults.color}
      strokeWidth={sw}
      strokeLinecap="round"
      strokeLinejoin="round">
      <Path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z" />
    </Svg>
  );
}

export function CommentIcon({size, color, filled}: IconProps) {
  return (
    <I size={size} color={color}>
      <Path
        d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"
        fill={filled ? color ?? defaults.color : 'none'}
        stroke={color ?? defaults.color}
      />
    </I>
  );
}

export function BookmarkIcon({size, color, filled}: IconProps) {
  return (
    <Svg
      width={size ?? defaults.size}
      height={size ?? defaults.size}
      viewBox="0 0 24 24"
      fill={filled ? color ?? defaults.color : 'none'}
      stroke={color ?? defaults.color}
      strokeWidth={defaults.strokeWidth}
      strokeLinecap="round"
      strokeLinejoin="round">
      <Path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z" />
    </Svg>
  );
}

export function RepostIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Polyline points="17 1 21 5 17 9" stroke={color ?? defaults.color} />
      <Path d="M3 11V9a4 4 0 0 1 4-4h14" stroke={color ?? defaults.color} />
      <Polyline points="7 23 3 19 7 15" stroke={color ?? defaults.color} />
      <Path d="M21 13v2a4 4 0 0 1-4 4H3" stroke={color ?? defaults.color} />
    </I>
  );
}

export function SearchIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Circle cx="11" cy="11" r="8" stroke={color ?? defaults.color} />
      <Line x1="21" y1="21" x2="16.65" y2="16.65" stroke={color ?? defaults.color} />
    </I>
  );
}

export function BellIcon({size, color, filled}: IconProps) {
  return (
    <I size={size} color={color}>
      <Path
        d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"
        fill={filled ? color ?? defaults.color : 'none'}
        stroke={color ?? defaults.color}
      />
      <Path d="M13.73 21a2 2 0 0 1-3.46 0" stroke={color ?? defaults.color} />
    </I>
  );
}

export function HomeIcon({size, color, filled}: IconProps) {
  return (
    <I size={size} color={color}>
      <Path
        d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"
        fill={filled ? color ?? defaults.color : 'none'}
        stroke={color ?? defaults.color}
      />
      <Polyline points="9 22 9 12 15 12 15 22" stroke={color ?? defaults.color} />
    </I>
  );
}

export function CompassIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Circle cx="12" cy="12" r="10" stroke={color ?? defaults.color} />
      <Path
        d="M16.24 7.76l-2.12 6.36-6.36 2.12 2.12-6.36 6.36-2.12z"
        fill={color ?? defaults.color}
        stroke={color ?? defaults.color}
      />
    </I>
  );
}

export function BookIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Path d="M4 19.5A2.5 2.5 0 0 1 6.5 17H20" stroke={color ?? defaults.color} />
      <Path
        d="M6.5 2H20v20H6.5A2.5 2.5 0 0 1 4 19.5v-15A2.5 2.5 0 0 1 6.5 2z"
        stroke={color ?? defaults.color}
      />
    </I>
  );
}

export function UserIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" stroke={color ?? defaults.color} />
      <Circle cx="12" cy="7" r="4" stroke={color ?? defaults.color} />
    </I>
  );
}

export function PenIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Path d="M12 20h9" stroke={color ?? defaults.color} />
      <Path
        d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"
        stroke={color ?? defaults.color}
      />
    </I>
  );
}

export function SettingsIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Circle cx="12" cy="12" r="3" stroke={color ?? defaults.color} />
      <Path
        d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1 0 2.83 2 2 0 0 1-2.83 0l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-2 2 2 2 0 0 1-2-2v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83 0 2 2 0 0 1 0-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1-2-2 2 2 0 0 1 2-2h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 0-2.83 2 2 0 0 1 2.83 0l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 2-2 2 2 0 0 1 2 2v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 0 2 2 0 0 1 0 2.83l-.06.06A1.65 1.65 0 0 0 19.4 9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 2 2 2 2 0 0 1-2 2h-.09a1.65 1.65 0 0 0-1.51 1z"
        stroke={color ?? defaults.color}
      />
    </I>
  );
}

export function ArrowLeftIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Line x1="19" y1="12" x2="5" y2="12" stroke={color ?? defaults.color} />
      <Polyline points="12 19 5 12 12 5" stroke={color ?? defaults.color} />
    </I>
  );
}

export function MoreDotsIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Circle cx="12" cy="12" r="1" fill={color ?? defaults.color} stroke={color ?? defaults.color} />
      <Circle cx="19" cy="12" r="1" fill={color ?? defaults.color} stroke={color ?? defaults.color} />
      <Circle cx="5" cy="12" r="1" fill={color ?? defaults.color} stroke={color ?? defaults.color} />
    </I>
  );
}

export function ShareIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Circle cx="18" cy="5" r="3" stroke={color ?? defaults.color} />
      <Circle cx="6" cy="12" r="3" stroke={color ?? defaults.color} />
      <Circle cx="18" cy="19" r="3" stroke={color ?? defaults.color} />
      <Line x1="8.59" y1="13.51" x2="15.42" y2="17.49" stroke={color ?? defaults.color} />
      <Line x1="15.41" y1="6.51" x2="8.59" y2="10.49" stroke={color ?? defaults.color} />
    </I>
  );
}

export function PlusIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Line x1="12" y1="5" x2="12" y2="19" stroke={color ?? defaults.color} />
      <Line x1="5" y1="12" x2="19" y2="12" stroke={color ?? defaults.color} />
    </I>
  );
}

export function CheckIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Polyline points="20 6 9 17 4 12" stroke={color ?? defaults.color} />
    </I>
  );
}

export function XIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Line x1="18" y1="6" x2="6" y2="18" stroke={color ?? defaults.color} />
      <Line x1="6" y1="6" x2="18" y2="18" stroke={color ?? defaults.color} />
    </I>
  );
}

export function ChevronRightIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Polyline points="9 18 15 12 9 6" stroke={color ?? defaults.color} />
    </I>
  );
}

export function ImageIcon({size, color}: IconProps) {
  return (
    <I size={size} color={color}>
      <Rect x="3" y="3" width="18" height="18" rx="2" ry="2" stroke={color ?? defaults.color} />
      <Circle cx="8.5" cy="8.5" r="1.5" stroke={color ?? defaults.color} />
      <Polyline points="21 15 16 10 5 21" stroke={color ?? defaults.color} />
