  1→import React from 'react';
  2→import {Image, Pressable, StyleSheet, Text, View} from 'react-native';
  3→import {useTheme} from '../../theme/ThemeProvider';
  4→import {fonts, typeScale} from '../../theme/typography';
  5→import {spacing, radii, shadows} from '../../theme/spacing';
  6→import {Avatar} from '../Avatar';
  7→import {ActionBar} from './ActionBar';
  8→
  9→interface PostCardProps {
 10→  title: string;
 11→  bodyPreview: string;
 12→  authorName: string;
 13→  authorAvatar?: string | null;
 14→  authorBadge?: 'legend' | 'og' | null;
 15→  bannerImage?: string | null;
 16→  postType?: string;
 17→  readingTime?: string;
 18→  likeCount: number;
 19→  commentCount: number;
 20→  bookmarkCount?: number;
 21→  isLiked?: boolean;
 22→  isBookmarked?: boolean;
 23→  onPress?: () => void;
 24→  onLike?: () => void;
 25→  onComment?: () => void;
 26→  onBookmark?: () => void;
 27→  onRepost?: () => void;
 28→}
 29→
 30→export function PostCard({
 31→  title,
 32→  bodyPreview,
 33→  authorName,
 34→  authorAvatar,
 35→  authorBadge,
 36→  bannerImage,
 37→  postType,
 38→  readingTime,
 39→  likeCount,
 40→  commentCount,
 41→  bookmarkCount,
 42→  isLiked,
 43→  isBookmarked,
 44→  onPress,
 45→  onLike,
 46→  onComment,
 47→  onBookmark,
 48→  onRepost,
 49→}: PostCardProps) {
 50→  const {colors} = useTheme();
 51→  const s = shadows(colors);
 52→
 53→  return (
 54→    <Pressable
 55→      onPress={onPress}
 56→      style={({pressed}) => [
 57→        styles.card,
 58→        {
 59→          backgroundColor: colors.bgCard,
 60→          borderColor: colors.borderCard,
 61→        },
 62→        s.card,
 63→        pressed && styles.pressed,
 64→      ]}>
 65→      {bannerImage ? (
