183→            <SkeletonLoader width="100%" height={16} style={{marginTop: 20}} />
184→            <SkeletonLoader width="100%" height={16} style={{marginTop: 8}} />
185→            <SkeletonLoader width="60%" height={16} style={{marginTop: 8}} />
186→          </View>
187→        </View>
188→      </SafeAreaView>
189→    );
190→  }
191→
192→  if (detailQuery.isError) {
