288→  async saveJournal(token: string, payload: { title: string; plainText: string; html?: string }): Promise<{ message?: string }> {
289→    const formData = new FormData();
290→
291→    const lexicalPayload = {
292→      root: {
293→        children: [
294→          {
295→            type: 'paragraph',
296→            children: [
297→              {
298→                type: 'text',
299→                text: payload.plainText,
300→                detail: 0,
301→                format: 0,
302→                mode: 'normal',
303→                style: '',
304→                version: 1,
305→              },
306→            ],
307→            direction: null,
308→            format: '',
309→            indent: 0,
310→            version: 1,
311→          },
312→        ],
313→        direction: null,
314→        format: '',
315→        indent: 0,
316→        type: 'root',
317→        version: 1,
318→      },
319→    };
320→
321→    formData.append('title', payload.title);
322→    formData.append('content', JSON.stringify(lexicalPayload));
323→    formData.append('post_type', 'text');
324→
325→    return apiRequest<{ message?: string }>('/save-journal', {
326→      method: 'POST',
327→      headers: {
328→        ...authHeaders(token),
329→      },
330→      body: formData,
331→      timeoutMs: 30000,
332→      retries: 0,
333→    });
334→  },
